var minimumAverage = function(nums) {
    nums.sort((a, b) => a - b);
    const n = nums.length;
    let mn = Infinity;
    for (let i = 0; i < n / 2; i++) {
        mn = Math.min(mn, (nums[i] + nums[n - 1 - i]) / 2);
    }
    return mn;
};
